_init_db()


# ----------------------------
# Helpers
# ----------------------------

def _now() -> float:
    return time.time()


def _uuid() -> str:
    return str(uuid.uuid4())


def _image_path(image_id: str, ext: str) -> str:
    return os.path.join(IMAGES_DIR, f"{image_id}{ext}")


def _safe_ext_from_content_type(ct: Optional[str]) -> str:
    if not ct:
        return ".bin"
    ct = ct.lower()
    if "jpeg" in ct or "jpg" in ct:
        return ".jpg"
    if "png" in ct:
        return ".png"
    if "webp" in ct:
        return ".webp"
    if "bmp" in ct:
        return ".bmp"
    return ".bin"


def _try_get_image_info(path: str) -> Tuple[Optional[int], Optional[int]]:
    try:
        with Image.open(path) as im:
            return im.size[0], im.size[1]
    except Exception:
        return None, None


def _recompute_aggregation(conn: sqlite3.Connection, image_id: str) -> Dict[str, Any]:
    cur = conn.cursor()
    cur.execute("SELECT label, COUNT(*) as c FROM annotations WHERE image_id = ? GROUP BY label", (image_id,))
    rows = cur.fetchall()
    if not rows:
        label = None
        votes = 0
        ties = 0
    else:
        counts = sorted([(r["label"], int(r["c"])) for r in rows], key=lambda x: (-x[1], x[0]))
        top_votes = counts[0][1]
        top_labels = [lbl for lbl, c in counts if c == top_votes]
        ties = 1 if len(top_labels) > 1 else 0
        label = top_labels[0] if len(top_labels) == 1 else top_labels[0]
        votes = top_votes
    cur.execute("""
        INSERT INTO aggregated_labels(image_id, label, votes, ties, updated_at)
        VALUES(?, ?, ?, ?, ?)
        ON CONFLICT(image_id) DO UPDATE SET
            label=excluded.label,
            votes=excluded.votes,
            ties=excluded.ties,
            updated_at=excluded.updated_at
    """, (image_id, label, votes, ties, _now()))
    conn.commit()
    return {"image_id": image_id, "label": label, "votes": votes, "ties": ties}


def _get_aggregated(conn: sqlite3.Connection, image_id: str) -> Dict[str, Any]:
    cur = conn.cursor()
    cur.execute("SELECT image_id, label, votes, ties, updated_at FROM aggregated_labels WHERE image_id = ?", (image_id,))
    r = cur.fetchone()
    if not r:
        return {"image_id": image_id, "label": None, "votes": 0, "ties": 0, "updated_at": None}
    return dict(r)


def _list_classes(conn: sqlite3.Connection) -> List[str]:
    cur = conn.cursor()
    cur.execute("SELECT DISTINCT label FROM aggregated_labels WHERE label IS NOT NULL")
    classes = sorted([r[0] for r in cur.fetchall()])
    return classes


def _get_training_samples(conn: sqlite3.Connection, min_majority: int) -> List[Tuple[str, str]]:
    cur = conn.cursor()
    cur.execute("""
        SELECT i.image_id, i.filename, a.label, a.votes, a.ties
        FROM images i
        JOIN aggregated_labels a ON a.image_id = i.image_id
        WHERE a.label IS NOT NULL AND a.votes >= ? AND a.ties = 0
    """, (min_majority,))
    rows = cur.fetchall()
    out = []
    for r in rows:
        out.append((r["image_id"], r["label"]))
    return out


def _load_image_tensor(path: str, image_size: int) -> torch.Tensor:
    with Image.open(path) as im:
        im = im.convert("RGB")
        im = im.resize((image_size, image_size))
        arr = np.asarray(im, dtype=np.float32) / 255.0
        arr = np.transpose(arr, (2, 0, 1))
        return torch.from_numpy(arr)


# ----------------------------
# Models / Training
# ----------------------------

class SimpleCNN(nn.Module):
    def __init__(self, num_classes: int, image_size: int):
        super().__init__()
        self.features = nn.Sequential(
            nn.Conv2d(3, 16, 3, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(2),
            nn.Conv2d(16, 32, 3, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(2),
            nn.Conv2d(32, 64, 3, padding=1),
            nn.ReLU(inplace=True),
            nn.MaxPool2d(2),
        )
        feat_size = image_size // (2 * 2 * 2)
        self.classifier = nn.Sequential(
            nn.Flatten(),
            nn.Linear(64 * feat_size * feat_size, 128),
            nn.ReLU(inplace=True),
            nn.Linear(128, num_classes),
        )

    def forward(self, x):
        x = self.features(x)
        x = self.classifier(x)
        return x


class LabeledImagesDataset(Dataset):
    def __init__(self, conn: sqlite3.Connection, samples: List[Tuple[str, str]], class_to_idx: Dict[str, int], image_size: int):
        self.conn = conn
        self.samples = samples
        self.class_to_idx = class_to_idx
        self.image_size = image_size

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx: int):
        image_id, label = self.samples[idx]
        cur = self.conn.cursor()
        cur.execute("SELECT filename FROM images WHERE image_id = ?", (image_id,))
        r = cur.fetchone()
        if not r:
            raise RuntimeError("Image not found in DB")
        path = r["filename"]
        x = _load_image_tensor(path, self.image_size)
        y = self.class_to_idx[label]
        return x, torch.tensor(y, dtype=torch.long)


def _train_model(run_id: str, params: Dict[str, Any]):
    with _db_lock:
        conn = _connect()
        cur = conn.cursor()
        cur.execute("UPDATE model_runs SET status = ? WHERE run_id = ?", ("running", run_id))
        conn.commit()

    try:
        device = params.get("device", DEFAULT_DEVICE)
        epochs = int(params.get("epochs", DEFAULT_EPOCHS))
        batch_size = int(params.get("batch_size", DEFAULT_BATCH_SIZE))
        lr = float(params.get("lr", DEFAULT_LR))
        image_size = int(params.get("image_size", DEFAULT_IMAGE_SIZE))
        min_majority = int(params.get("min_majority", DEFAULT_MIN_MAJORITY))

        with _db_lock:
            conn = _connect()
            classes = _list_classes(conn)
            samples = _get_training_samples(conn, min_majority=min_majority)
            num_samples = len(samples)
            if num_samples == 0 or len(classes) == 0:
                raise RuntimeError("No training samples available (need aggregated labels with sufficient majority and no ties).")
            class_to_idx = {c: i for i, c in enumerate(classes)}

        dataset = LabeledImagesDataset(conn, samples, class_to_idx, image_size=image_size)
        loader = DataLoader(dataset, batch_size=batch_size, shuffle=True, num_workers=0)

        model = SimpleCNN(num_classes=len(classes), image_size=image_size).to(device)
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(model.parameters(), lr=lr)

        model.train()
        for _ in range(epochs):
            for xb, yb in loader:
                xb = xb.to(device)
                yb = yb.to(device)
                optimizer.zero_grad(set_to_none=True)
                logits = model(xb)
                loss = criterion(logits, yb)
                loss.backward()
                optimizer.step()

        model_path = os.path.join(MODEL_DIR, f"{run_id}.pt")
        payload = {
            "state_dict": model.state_dict(),
            "classes": classes,
            "image_size": image_size,
            "arch": "SimpleCNN",
            "created_at": _now(),
        }
        torch.save(payload, model_path)

        with _db_lock:
            conn2 = _connect()
            cur2 = conn2.cursor()
            cur2.execute(
                "UPDATE model_runs SET status=?, classes_json=?, num_samples=?, model_path=?, error=? WHERE run_id=?",
                ("completed", json.dumps(classes), num_samples, model_path, None, run_id),
            )
            conn2.commit()
            conn2.close()

    except Exception as e:
        with _db_lock:
            conn3 = _connect()
            cur3 = conn3.cursor()
            cur3.execute(
                "UPDATE model_runs SET status=?, error=? WHERE run_id=?",
                ("failed", str(e), run_id),
            )
            conn3.commit()
            conn3.close()


