@app.post("/images")
async def upload_image(file: UploadFile = File(...)):
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file")

    image_id = _uuid()
    ext = _safe_ext_from_content_type(file.content_type)
    path = _image_path(image_id, ext)
    with open(path, "wb") as f:
        f.write(content)

    width, height = _try_get_image_info(path)
    created_at = _now()

    with _db_lock:
        conn = _connect()
        cur = conn.cursor()
        cur.execute("""
            INSERT INTO images(image_id, filename, original_filename, content_type, bytes_size, width, height, created_at)
            VALUES(?, ?, ?, ?, ?, ?, ?, ?)
        """, (image_id, path, file.filename, file.content_type, len(content), width, height, created_at))
        conn.commit()
        conn.close()

    return {
        "image_id": image_id,
        "stored_path": path,
        "original_filename": file.filename,
        "content_type": file.content_type,
        "bytes_size": len(content),
        "width": width,
        "height": height,
        "created_at": created_at,
    }


