@app.post("/images/{image_id}/annotations")
def submit_annotation(image_id: str, payload: AnnotationIn):
    with _db_lock:
        conn = _connect()
        cur = conn.cursor()
        cur.execute("SELECT image_id FROM images WHERE image_id = ?", (image_id,))
        if not cur.fetchone():
            conn.close()
            raise HTTPException(status_code=404, detail="Image not found")

        annotation_id = _uuid()
        try:
            cur.execute("""
                INSERT INTO annotations(annotation_id, image_id, annotator_id, label, created_at)
                VALUES(?, ?, ?, ?, ?)
                ON CONFLICT(image_id, annotator_id) DO UPDATE SET
                    label=excluded.label,
                    created_at=excluded.created_at
            """, (annotation_id, image_id, payload.annotator_id, payload.label, _now()))
        except sqlite3.IntegrityError as e:
            conn.close()
            raise HTTPException(status_code=400, detail=f"Integrity error: {str(e)}")

        agg = _recompute_aggregation(conn, image_id)
        conn.close()

    return {"annotation_saved": True, "aggregated": agg}


@app.get("/images/{image_id}/annotations")
def list_annotations(image_id: str):
    with _db_lock:
        conn = _connect()
        cur = conn.cursor()
        cur.execute("SELECT image_id FROM images WHERE image_id = ?", (image_id,))
        if not cur.fetchone():
            conn.close()
            raise HTTPException(status_code=404, detail="Image not found")

        cur.execute("""
            SELECT annotation_id, image_id, annotator_id, label, created_at
            FROM annotations
            WHERE image_id = ?
            ORDER BY created_at ASC
        """, (image_id,))
        rows = [dict(r) for r in cur.fetchall()]
        agg = _get_aggregated(conn, image_id)
        conn.close()

    return {"image_id": image_id, "annotations": rows, "aggregated": agg}


@app.get("/aggregated")
def list_aggregated(limit: int = 100, offset: int = 0):
    limit = max(1, min(1000, int(limit)))
    offset = max(0, int(offset))
    with _db_lock:
        conn = _connect()
        cur = conn.cursor()
        cur.execute("""
            SELECT a.image_id, a.label, a.votes, a.ties, a.updated_at, i.filename, i.width, i.height, i.created_at
            FROM aggregated_labels a
            JOIN images i ON i.image_id = a.image_id
            ORDER BY a.updated_at DESC
            LIMIT ? OFFSET ?
        """, (limit, offset))
        rows = [dict(r) for r in cur.fetchall()]
        conn.close()
    return {"items": rows, "limit": limit, "offset": offset}


