@app.get("/stats")
def stats():
    with _db_lock:
        conn = _connect()
        cur = conn.cursor()
        cur.execute("SELECT COUNT(*) FROM images")
        n_images = int(cur.fetchone()[0])
        cur.execute("SELECT COUNT(*) FROM annotations")
        n_annotations = int(cur.fetchone()[0])
        cur.execute("SELECT COUNT(*) FROM aggregated_labels WHERE label IS NOT NULL")
        n_aggregated = int(cur.fetchone()[0])
        cur.execute("SELECT COUNT(*) FROM aggregated_labels WHERE ties = 1")
        n_ties = int(cur.fetchone()[0])
        classes = _list_classes(conn)
        conn.close()
    return {
        "images": n_images,
        "annotations": n_annotations,
        "aggregated_labeled": n_aggregated,
        "ties": n_ties,
        "classes": classes,
    }


@app.post("/train")
def train(req: TrainRequest = Body(default=TrainRequest())):
    params = req.model_dump()
    run_id = _uuid()
    created_at = _now()

    with _db_lock:
        conn = _connect()
        cur = conn.cursor()
        cur.execute("""
            INSERT INTO model_runs(run_id, created_at, status, params_json, classes_json, num_samples, model_path, error)
            VALUES(?, ?, ?, ?, ?, ?, ?, ?)
        """, (run_id, created_at, "queued", json.dumps(params), None, None, None, None))
        conn.commit()
        conn.close()

    t = threading.Thread(target=_train_model, args=(run_id, params), daemon=True)
    t.start()

    return {"run_id": run_id, "status": "queued", "created_at": created_at, "params": params}


@app.get("/train/{run_id}")
def get_train_run(run_id: str):
    with _db_lock:
        conn = _connect()
        cur = conn.cursor()
        cur.execute("SELECT * FROM model_runs WHERE run_id = ?", (run_id,))
        r = cur.fetchone()
        conn.close()
    if not r:
        raise HTTPException(status_code=404, detail="Run not found")
    out = dict(r)
    out["params"] = json.loads(out["params_json"]) if out.get("params_json") else None
    out["classes"] = json.loads(out["classes_json"]) if out.get("classes_json") else None
    return out


